import React from 'react';

import Button from '@components/ui/Button';
import Icon from '@components/ui/Icon';
import * as styles from './emptyGfx.module.css';

/**
 * Displays Graphics centered vertically and horizontally. Mostly used when displaying empty lists
 * @param {Object} prop Prop passed to this component
 * @param {string} prop.icon Icon graphics
 * @param {?string} [prop.note] Note to display
 * @param {?()=>{}} [prop.ctaFn] Callback fn to execute once user clicks the 'Call-To-Action' button
 * @param {?string} [prop.ctaBtnText='Load'] Text to display on the CTA button
 */
export default function EmptyGfx({ icon, note, ctaFn, ctaBtnText }) {
	return (
		<div className={styles.emptyGfxC}>
			<div>
				<Icon icon={icon} />
				{note && <div>{note}</div>}
				{ctaFn && typeof ctaFn === 'function' && (
					<Button variant="primary" size="big" isDark={true} onClick={ctaFn}>
						{ctaBtnText || 'Load'}
					</Button>
				)}
			</div>
		</div>
	);
}
