import React, { useEffect, useState } from 'react';
import { createPortal } from 'react-dom';
import clsx from 'clsx';

import * as styles from './bottomSheet.module.css';

/**
 * React component that displays content inside a bottomsheet
 * Bottomsheet is rendered inside the body tag using createPortal() react-dom API
 * @param {Object} prop - React prop
 * @param {string} [prop.title] - Bottom sheet title
 * @param {string} [prop.desc] - Short description
 * @param {Boolean} [prop.useCloseBtn=false] - Whether to show the close button
 * @param {()=>{}} [prop.doOnOpen] - Callback function to execute once bottom sheet is opened
 * @param {()=>{}} [prop.doOnClose] - Callback function to execute once bottom sheet is closed
 * @param {(close:Function)=>{}|JSX.Element} prop.children - (close)=>{} or React element
 */
export default function BottomSheet({ title, desc, useCloseBtn, doOnOpen, doOnClose, children }) {
	const [isVisible, setIsVisible] = useState(false);
	const [sheetTitle, setSheetTitle] = useState(title || '');

	const _openBtmSheet = () => {
		document && document.body && (document.body.style.overflow = 'hidden');
		setTimeout(() => {
			setIsVisible(true);
			doOnOpen &&
				typeof doOnOpen == 'function' &&
				setTimeout(() => {
					doOnOpen();
				}, 200);
		}, 10); //a slight delay of 10ms jst for CSS transition state-change to take effect
	};
	const close = () => {
		setIsVisible(false);
		setTimeout(() => {
			document && document.body && (document.body.style.overflow = 'visible');
			doOnClose && typeof doOnClose == 'function' && doOnClose();
		}, 200);
	};

	useEffect(() => {
		_openBtmSheet();

		// document && document.body && (document.body.style.overflow = 'hidden');
		// return () => {
		// 	document && document.body && (document.body.style.overflow = 'visible');
		// };
	}, []);

	// return (
	// 	<div className={clsx(styles.wrap, isVisible && styles.isViz)}>
	// 		{useCloseBtn ? <div className={styles.bg}></div> : <div className={styles.bg} onClick={close}></div>}
	// 		<div className={styles.sheet}>
	// 			{(title || desc) && (
	// 				<header>
	// 					{title && <div>{title}</div>}
	// 					{desc && <div>{desc}</div>}
	// 				</header>
	// 			)}
	// 			<main>{typeof children == 'function' ? children(close) : children}</main>
	// 			{useCloseBtn && (
	// 				<button className={styles.xBtn} onClick={close}>
	// 					&#10006;
	// 				</button>
	// 			)}
	// 		</div>
	// 	</div>
	// );
	return createPortal(
		<div className={clsx(styles.wrap, isVisible && styles.isViz)}>
			{useCloseBtn ? <div className={styles.bg}></div> : <div className={styles.bg} onClick={close}></div>}
			<div className={styles.sheet}>
				{(sheetTitle || desc) && (
					<header>
						{sheetTitle && <div>{sheetTitle}</div>}
						{desc && <div>{desc}</div>}
					</header>
				)}
				<main>{typeof children == 'function' ? children(close, setSheetTitle) : children}</main>
				{useCloseBtn && (
					<button className={styles.xBtn} onClick={close}>
						&#10006;
					</button>
				)}
			</div>
		</div>,
		document.body,
	);
}

