export function withBottomSheet(ComponentToBeWrappedInBtmSheet) {
	// return (
	// 	<BottomSheet>
	// 		<ComponentToBeWrappedInBtmSheet />
	// 	</BottomSheet>
	// );
	return function BottomSheetHoc({ title, desc, useCloseBtn, doOnClose }) {
		return (
			<BottomSheet title={title} desc={desc} useCloseBtn={useCloseBtn} doOnClose={doOnClose}>
				<ComponentToBeWrappedInBtmSheet />
			</BottomSheet>
		);
	};
}
