import React from 'react';

import * as styles from './pagination.module.css';

/**
 * Displays pagination
 * @param {Object} props props passed to this component
 * @param {number} props.totalPages Total number of pages
 * @param {number} props.currentPage Page that is currently active
 * @param {(number)=>{}} props.goToPage Callback function that fires on page-button click. Argument is the page-number to activate
 */
export default function Pagination({ totalPages, currentPage, goToPage }) {
	//'totalPages' is same as the last page
	// basePath = basePath || ''; //eg -- 'projects'
	// pageNumPrefix = pageNumPrefix || ''; //eg' -- 'page-' would yield a url like 'projects/page-2'
	return (
		1 < totalPages && (
			<div className={styles.paginationLinks}>
				{
					//1 separator 3 4 '5' 6 7 separator 9	//thus we can see that if there are 9 or less pages, we do not need separators
					9 < totalPages ? ( //if num pages are more than 9, we only render links to first page, last page and 2 pages before and after current page
						//1 .... 5 6 '7' 8 9 .... 24
						currentPage < 6 ? ( //if current page is less than 6 (ie within first 5 pages), render the first page-links in series and then render the link to last page
							//1 2 '3' 4 5 .... 12				//handles this scenario
							//1 2 3 4 '5' 6 7 .... 12			//handles this scenario

							<>
								<PaginationSeries seriesStart={1} seriesEnd={currentPage + 2} currentPage={currentPage} />
								<span className={styles.separator}>...</span>
								<button
									onClick={() => {
										goToPage(totalPages);
									}}
								>
									{totalPages}
								</button>
							</>
						) : currentPage > totalPages - 5 ? ( //else if current page is within the last 5 pages, render the link to first page and then render last page-links in series
							//1 .... 6 7 '8' 9 10 11 12			//handles this scenario
							//1 .... 9 10 '11' 12				//handles this scenario
							<>
								<button
									onClick={() => {
										goToPage(1);
									}}
								>
									1
								</button>
								<span className={styles.separator}>...</span>
								<PaginationSeries seriesStart={currentPage - 2} seriesEnd={totalPages} currentPage={currentPage} />
							</>
						) : (
							//else if current page is more than 6 and less than last-page - 5
							//1 .... 4 5 '6' 7 8 .... 11	//handles this scenario
							<>
								<button
									onClick={() => {
										goToPage(1);
									}}
								>
									1
								</button>
								<span className={styles.separator}>...</span>
								<PaginationSeries seriesStart={currentPage - 2} seriesEnd={currentPage + 2} currentPage={currentPage} />
								<span className={styles.separator}>...</span>
								<button
									onClick={() => {
										goToPage(totalPages);
									}}
								>
									{totalPages}
								</button>
							</>
						)
					) : (
						//else if num pages are 9 or less
						//1 2 3 4 5 6 '7' 8 9
						<PaginationSeries seriesStart={1} seriesEnd={totalPages} currentPage={currentPage} goToPage={goToPage} />
					)
				}
			</div>
		)
	);
}

function PaginationSeries({ seriesStart, seriesEnd, currentPage, goToPage }) {
	return (
		//for(let i = seriesStart; i <= seriesEnd; i++){}
		Array.from({ length: seriesEnd - seriesStart + 1 }, (_, i) =>
			//i + seriesStart gives us the page # currently being looped
			currentPage === i + seriesStart ? (
				<span key={`pn${i + seriesStart}`} className={styles.current}>
					{currentPage}
				</span>
			) : (
				<button
					key={`pn${i + seriesStart}`}
					onClick={() => {
						goToPage(i + seriesStart);
					}}
				>
					{i + seriesStart}
				</button>
			),
		)
	);
}
